#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,B,M; scanf("%d %d %d",&N,&B,&M);
        long long loads=0; long long curBlock=-1;
        for(int i=0;i<M;i++){
            int x; scanf("%d",&x);
            long long blk = x / B;
            if(blk!=curBlock){
                loads++;
                curBlock=blk;
            }
        }
        printf("%lld\n",loads);
    }
    return 0;
}

